document.addEventListener('DOMContentLoaded', function() {
    // 1. เลือกฟอร์มค้นหา (ครอบคลุมทั้ง Bricks และ Elementor)
    const searchForms = document.querySelectorAll('form[role="search"], .bricks-element-search form, .elementor-search-form');

    searchForms.forEach(form => {
        form.addEventListener('submit', function(e) {
            // ดึงค่า Input ที่มีชื่อว่า "s"
            const searchInput = form.querySelector('input[name="s"]');

            if (searchInput && searchInput.value.trim() !== "") {
                e.preventDefault(); // สั่งไม่ให้ฟอร์มส่งค่าแบบปกติ (?s=...)

                const query = encodeURIComponent(searchInput.value.trim());
                // 2. สร้าง URL ใหม่ในรูปแบบ /search/keyword
                const targetUrl = window.location.origin + '/search/?s_a=' + query + '&s_v=' +  query;

                // 3. วิ่งไปที่ URL ใหม่ทันที
                window.location.href = targetUrl;
            }
        });
    });
});
